I used `eval` for this (in TypeScript): 

```ts
    function hIfBinaryExpr(
        this: any,
        left: unknown, operator: string, right: unknown,
        options: Handlebars.HelperOptions
    ) {
        // eslint-disable-next-line no-eval
        const evaluation: boolean = eval(`left ${operator} right`);
        return evaluation ? options.fn(this) : options.inverse(this);
    }
```

